static inline std::vector<int64_t> infer_output_shape(const at::Tensor& x, const at::Tensor& w) {
    // x: [N, Cin, D, H, W]
    // w: [Cin, Cout, KD, KH, KW]
    TORCH_CHECK(x.dim() == 5, \"x must be 5D\");
    TORCH_CHECK(w.dim() == 5, \"weight must be 5D\");
    TORCH_CHECK(x.size(1) == w.size(0), \"Cin mismatch between x and weight\");

    const int64_t N  = x.size(0);
    const int64_t Cin = x.size(1);
    const int64_t Din = x.size(2);
    const int64_t Hin = x.size(3);
    const int64_t Win = x.size(4);

    const int64_t Cout = w.size(1);
    const int64_t Kd = w.size(2);
    const int64_t Kh = w.size(3);
    const int64_t Kw = w.size(4);

    const int64_t Dout = Din + Kd - 1;
    const int64_t Hout = Hin + Kh - 1;
    const int64_t Wout = Win + Kw - 1;

    return {N, Cout, Dout, Hout, Wout};
}

at::Tensor conv_transposed_3d_square_input_square_kernel_custom_impl_npu(const at::Tensor& x, const at::Tensor& weight) {
    auto y_sizes = infer_output_shape(x, weight);
    at::Tensor y = at::empty(y_sizes, x.options().dtype(at::kFloat));
    EXEC_NPU_CMD(aclnnConvTransposed3dSquareInputSquareKernelCustom, x, weight, y);
    return y;
}

